const dot = document.getElementById("cursor-dot");
const ring = document.getElementById("cursor-ring");
let rx = 0,
  ry = 0,
  mx = 0,
  my = 0;

document.addEventListener("mousemove", (e) => {
  mx = e.clientX;
  my = e.clientY;
  dot.style.left = mx + "px";
  dot.style.top = my + "px";
});

(function lerpRing() {
  rx += (mx - rx) * 0.14;
  ry += (my - ry) * 0.14;
  ring.style.left = rx + "px";
  ring.style.top = ry + "px";
  requestAnimationFrame(lerpRing);
})();

/* ── MARQUEE ─────────────────────────────────────────── */
const items = [
  "Glitch",
  "Aurora",
  "Glassmorphism",
  "Scramble",
  "Spotlight",
  "Conic Border",
  "3D Tilt",
  "Noise",
  "Counter"
];
const track = document.getElementById("marquee");
const make = () =>
  items
    .map(
      (t) =>
        `<span class="marquee-item">${t}</span><span class="marquee-sep">✦</span>`
    )
    .join("");
track.innerHTML = make() + make(); // duplicate for seamless loop

/* ── 3D TILT ─────────────────────────────────────────── */
document.querySelectorAll("[data-tilt]").forEach((card) => {
  card.addEventListener("mousemove", (e) => {
    const r = card.getBoundingClientRect();
    const x = (e.clientX - r.left) / r.width - 0.5;
    const y = (e.clientY - r.top) / r.height - 0.5;
    card.style.transform = `perspective(700px) rotateY(${x * 14}deg) rotateX(${
      -y * 14
    }deg) scale(1.03)`;
  });
  card.addEventListener("mouseleave", () => {
    card.style.transition =
      "transform .6s cubic-bezier(.23,1,.32,1), box-shadow .4s";
    card.style.transform = "";
    setTimeout(() => (card.style.transition = ""), 600);
  });
  card.addEventListener("mouseenter", () => {
    card.style.transition = "transform .12s ease, box-shadow .4s";
  });
});

/* ── TEXT SCRAMBLE ───────────────────────────────────── */
const CHARS = "!<>-_\\/[]{}—=+*^?#░▒▓│┤╡╢╖╕╣║╗╝╜╛┐└┴┬├─┼╞╟╚╔╩╦╠═╬╧╨╤╥╙╘╒╓╫╪┘┌";
const scrambleEl = document.getElementById("scramble-text");
const PHRASES = [
  "no libraries. no mercy.",
  "your cursor > their framework.",
  "ship it. no deps. no regrets.",
  "the browser is enough.",
  "pure css goes hard. ✦"
];
let phraseIdx = 0;
let scrambleTimer = null;

function scramble(el, newText) {
  clearInterval(scrambleTimer);
  const len = Math.max(el.innerText.length, newText.length);
  let iter = 0;
  scrambleTimer = setInterval(() => {
    el.innerText = newText
      .split("")
      .map((ch, i) => {
        if (i < iter) return newText[i];
        if (ch === " ") return " ";
        return CHARS[Math.floor(Math.random() * CHARS.length)];
      })
      .join("");
    if (iter >= len + 4) clearInterval(scrambleTimer);
    iter += 0.6;
  }, 38);
}

scrambleEl.addEventListener("mouseenter", () => {
  phraseIdx = (phraseIdx + 1) % PHRASES.length;
  scramble(scrambleEl, PHRASES[phraseIdx]);
});

scramble(scrambleEl, PHRASES[0]); // init

/* ── SPOTLIGHT CANVAS ────────────────────────────────── */
const spotSection = document.querySelector(".spotlight-section");
const canvas = document.getElementById("spotlight-canvas");
const ctx = canvas.getContext("2d");
let slx = -999,
  sly = -999;

function resizeCanvas() {
  const r = spotSection.getBoundingClientRect();
  canvas.width = r.width;
  canvas.height = r.height;
}

resizeCanvas();
window.addEventListener("resize", resizeCanvas);

spotSection.addEventListener("mousemove", (e) => {
  const r = spotSection.getBoundingClientRect();
  slx = e.clientX - r.left;
  sly = e.clientY - r.top;
});

spotSection.addEventListener("mouseleave", () => {
  slx = -999;
  sly = -999;
});

(function drawSpotlight() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  if (slx !== -999) {
    const g = ctx.createRadialGradient(slx, sly, 0, slx, sly, 260);
    g.addColorStop(0, "rgba(179,255,200,.12)");
    g.addColorStop(0.5, "rgba(94,173,255,.06)");
    g.addColorStop(1, "transparent");
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }
  requestAnimationFrame(drawSpotlight);
})();

/* ── SCROLL REVEAL ───────────────────────────────────── */
const reveals = document.querySelectorAll(".reveal");
const io = new IntersectionObserver(
  (entries) => {
    entries.forEach((e) => {
      if (e.isIntersecting) e.target.classList.add("in-view");
    });
  },
  { threshold: 0.12 }
);
reveals.forEach((el) => io.observe(el));

/* ── ANIMATED COUNTERS ───────────────────────────────── */
const counters = document.querySelectorAll(".stat-num");
const cio = new IntersectionObserver(
  (entries) => {
    entries.forEach((entry) => {
      if (!entry.isIntersecting) return;
      const el = entry.target;
      const target = +el.dataset.target;
      const dur = 1800;
      let start = null;
      const ease = (t) =>
        t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
      (function tick(ts) {
        if (!start) start = ts;
        const p = Math.min((ts - start) / dur, 1);
        el.textContent = Math.floor(ease(p) * target).toLocaleString();
        if (p < 1) requestAnimationFrame(tick);
        else el.textContent = target.toLocaleString();
      })(performance.now());
      cio.unobserve(el);
    });
  },
  { threshold: 0.5 }
);
counters.forEach((el) => cio.observe(el));

style.css:
@import url("https://fonts.googleapis.com/css2?family=Unbounded:wght@200;400;700;900&family=DM+Mono:ital@0;1&display=swap");

/* ── RESET & TOKENS ─────────────────────────────── */
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --c-bg: #070709;
  --c-surface: rgba(255, 255, 255, 0.04);
  --c-border: rgba(255, 255, 255, 0.1);
  --c-text: #e8e6f0;
  --c-muted: rgba(232, 230, 240, 0.35);
  --c-accent1: #b3ffc8;
  --c-accent2: #ff6ef7;
  --c-accent3: #5eadff;
  --font-display: "Unbounded", sans-serif;
  --font-mono: "DM Mono", monospace;
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--c-bg);
  color: var(--c-text);
  font-family: var(--font-mono);
  min-height: 100vh;
  overflow-x: hidden;
  cursor: none;
}

/* ── CUSTOM CURSOR ──────────────────────────────── */
#cursor-dot {
  width: 8px;
  height: 8px;
  background: var(--c-accent1);
  border-radius: 50%;
  position: fixed;
  top: 0;
  left: 0;
  pointer-events: none;
  z-index: 9999;
  transform: translate(-50%, -50%);
  transition: transform 0.1s, width 0.2s, height 0.2s, background 0.2s;
  mix-blend-mode: exclusion;
}

#cursor-ring {
  width: 36px;
  height: 36px;
  border: 1.5px solid rgba(179, 255, 200, 0.5);
  border-radius: 50%;
  position: fixed;
  top: 0;
  left: 0;
  pointer-events: none;
  z-index: 9998;
  transform: translate(-50%, -50%);
  transition: transform 0.12s cubic-bezier(0.23, 1, 0.32, 1), width 0.3s,
    height 0.3s, border-color 0.3s;
}

body:has(a:hover) #cursor-dot,
body:has(.card:hover) #cursor-dot {
  width: 16px;
  height: 16px;
  background: var(--c-accent2);
}
body:has(a:hover) #cursor-ring,
body:has(.card:hover) #cursor-ring {
  width: 64px;
  height: 64px;
  border-color: var(--c-accent2);
}

/* ── AURORA MESH BACKGROUND ─────────────────────── */
.aurora {
  position: fixed;
  inset: 0;
  z-index: 0;
  overflow: hidden;
  pointer-events: none;
}

.aurora-blob {
  position: absolute;
  border-radius: 50%;
  filter: blur(80px);
  opacity: 0.18;
  animation: aurora-drift 16s ease-in-out infinite alternate;
}

.aurora-blob:nth-child(1) {
  width: 70vw;
  height: 60vh;
  background: radial-gradient(circle, #b3ffc8 0%, transparent 70%);
  top: -20%;
  left: -10%;
  animation-duration: 14s;
}
.aurora-blob:nth-child(2) {
  width: 50vw;
  height: 70vh;
  background: radial-gradient(circle, #ff6ef7 0%, transparent 70%);
  top: 20%;
  right: -15%;
  animation-duration: 18s;
  animation-delay: -6s;
}
.aurora-blob:nth-child(3) {
  width: 55vw;
  height: 55vh;
  background: radial-gradient(circle, #5eadff 0%, transparent 70%);
  bottom: -10%;
  left: 30%;
  animation-duration: 20s;
  animation-delay: -3s;
}

@keyframes aurora-drift {
  0% {
    transform: translate(0, 0) scale(1);
  }
  33% {
    transform: translate(6vw, -4vh) scale(1.08);
  }
  66% {
    transform: translate(-4vw, 5vh) scale(0.95);
  }
  100% {
    transform: translate(3vw, 2vh) scale(1.05);
  }
}

/* Noise overlay */
.noise {
  position: fixed;
  inset: 0;
  z-index: 1;
  opacity: 0.045;
  pointer-events: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size: 200px 200px;
}

/* ── LAYOUT ─────────────────────────────────────── */
.page {
  position: relative;
  z-index: 2;
}

section {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 6rem 2rem;
  gap: 3rem;
}

.tag {
  font-family: var(--font-mono);
  font-size: 0.7rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--c-muted);
  border: 1px solid var(--c-border);
  padding: 0.35rem 0.8rem;
  border-radius: 2rem;
}

/* ── EFFECT 1: GLITCH HERO TEXT ─────────────────── */
.hero {
  position: relative;
}

.glitch-wrap {
  position: relative;
  display: inline-block;
}

.glitch {
  font-family: var(--font-display);
  font-size: clamp(3.5rem, 12vw, 10rem);
  font-weight: 900;
  line-height: 0.9;
  letter-spacing: -0.04em;
  background: linear-gradient(
    135deg,
    var(--c-accent1) 0%,
    var(--c-accent3) 50%,
    var(--c-accent2) 100%
  );
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  position: relative;
  animation: glitch-main 5s infinite;
}

.glitch::before,
.glitch::after {
  content: attr(data-text);
  position: absolute;
  top: 0;
  left: 0;
  font-family: var(--font-display);
  font-size: inherit;
  font-weight: inherit;
  line-height: inherit;
  letter-spacing: inherit;
  pointer-events: none;
}

.glitch::before {
  -webkit-text-fill-color: var(--c-accent2);
  clip-path: polygon(0 30%, 100% 30%, 100% 50%, 0 50%);
  animation: glitch-before 5s infinite;
  opacity: 0.7;
}

.glitch::after {
  -webkit-text-fill-color: var(--c-accent3);
  clip-path: polygon(0 60%, 100% 60%, 100% 80%, 0 80%);
  animation: glitch-after 5s infinite;
  opacity: 0.7;
}

@keyframes glitch-main {
  0%,
  94%,
  100% {
    transform: none;
  }
  95% {
    transform: skewX(-0.5deg);
  }
  96% {
    transform: skewX(0.8deg) translateX(-3px);
  }
  97% {
    transform: none;
  }
  98% {
    transform: translateX(3px);
  }
  99% {
    transform: skewX(-0.3deg);
  }
}

@keyframes glitch-before {
  0%,
  94%,
  100% {
    transform: none;
    opacity: 0;
  }
  95% {
    transform: translateX(-6px);
    opacity: 0.7;
  }
  96% {
    transform: translateX(4px) scaleY(1.02);
    opacity: 0.7;
  }
  97% {
    transform: none;
    opacity: 0;
  }
  98%,
  99% {
    transform: translateX(-3px);
    opacity: 0.5;
  }
}

@keyframes glitch-after {
  0%,
  95%,
  100% {
    transform: none;
    opacity: 0;
  }
  96% {
    transform: translateX(6px);
    opacity: 0.7;
  }
  97% {
    transform: translateX(-4px);
    opacity: 0.7;
  }
  98% {
    transform: none;
    opacity: 0;
  }
  99% {
    transform: translateX(2px);
    opacity: 0.4;
  }
}

.hero-sub {
  font-family: var(--font-mono);
  font-size: clamp(0.8rem, 2vw, 1.1rem);
  color: var(--c-muted);
  letter-spacing: 0.08em;
  margin-top: 1.5rem;
  overflow: hidden;
}

.hero-sub span {
  display: inline-block;
  animation: reveal-up 0.8s cubic-bezier(0.16, 1, 0.3, 1) both;
}

.hero-sub span:nth-child(2) {
  animation-delay: 0.15s;
}
.hero-sub span:nth-child(3) {
  animation-delay: 0.3s;
}
.hero-sub span:nth-child(4) {
  animation-delay: 0.45s;
}

@keyframes reveal-up {
  from {
    transform: translateY(120%);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

/* ── EFFECT 2: GLASS CARDS ──────────────────────── */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.5rem;
  width: 100%;
  max-width: 900px;
}

.card {
  position: relative;
  border-radius: 20px;
  padding: 2rem;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  backdrop-filter: blur(20px) saturate(1.4);
  -webkit-backdrop-filter: blur(20px) saturate(1.4);
  overflow: hidden;
  transition: transform 0.4s cubic-bezier(0.23, 1, 0.32, 1), box-shadow 0.4s;
  transform-style: preserve-3d;
  cursor: none;
}

/* Shimmer sweep on hover */
.card::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    105deg,
    transparent 40%,
    rgba(255, 255, 255, 0.07) 50%,
    transparent 60%
  );
  background-size: 200% 100%;
  background-position: -100% 0;
  transition: background-position 0.6s ease;
  border-radius: inherit;
  pointer-events: none;
}

.card:hover::before {
  background-position: 200% 0;
}

/* Glow border on hover */
.card::after {
  content: "";
  position: absolute;
  inset: -1px;
  border-radius: 21px;
  background: conic-gradient(
    from var(--angle, 0deg),
    var(--c-accent1),
    var(--c-accent2),
    var(--c-accent3),
    var(--c-accent1)
  );
  z-index: -1;
  opacity: 0;
  transition: opacity 0.4s;
  animation: border-spin 4s linear infinite;
}

.card:hover::after {
  opacity: 1;
}

@property --angle {
  syntax: "<angle>";
  initial-value: 0deg;
  inherits: false;
}

@keyframes border-spin {
  to {
    --angle: 360deg;
  }
}

.card-icon {
  font-size: 2rem;
  margin-bottom: 1rem;
  display: block;
}

.card-title {
  font-family: var(--font-display);
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  margin-bottom: 0.5rem;
  color: var(--c-text);
}

.card-desc {
  font-size: 0.75rem;
  line-height: 1.7;
  color: var(--c-muted);
  font-style: italic;
}

/* ── EFFECT 3: MARQUEE ──────────────────────────── */
.marquee-wrap {
  width: 100%;
  overflow: hidden;
  border-top: 1px solid var(--c-border);
  border-bottom: 1px solid var(--c-border);
  padding: 1.2rem 0;
}

.marquee-track {
  display: flex;
  width: max-content;
  animation: marquee-scroll 22s linear infinite;
  gap: 3rem;
}

.marquee-wrap:hover .marquee-track {
  animation-play-state: paused;
}

.marquee-item {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 200;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  white-space: nowrap;
  color: var(--c-muted);
  transition: color 0.3s;
}

.marquee-item:hover {
  color: var(--c-accent1);
}

.marquee-sep {
  color: var(--c-accent2);
  margin: 0;
}

@keyframes marquee-scroll {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(-50%);
  }
}

/* ── EFFECT 4: SCRAMBLE TEXT ────────────────────── */
#scramble-text {
  font-family: var(--font-display);
  font-size: clamp(1.5rem, 5vw, 3.5rem);
  font-weight: 400;
  letter-spacing: -0.03em;
  text-align: center;
  cursor: none;
  color: var(--c-text);
  max-width: 700px;
  line-height: 1.2;
}

.scramble-hint {
  font-size: 0.7rem;
  color: var(--c-muted);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  margin-top: 1rem;
}

/* ── EFFECT 5: SPOTLIGHT ────────────────────────── */
.spotlight-section {
  position: relative;
  min-height: 60vh;
}

#spotlight-canvas {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  opacity: 0;
  transition: opacity 0.4s;
}

.spotlight-section:hover #spotlight-canvas {
  opacity: 1;
}

.spotlight-content {
  position: relative;
  z-index: 1;
  text-align: center;
}

.big-label {
  font-family: var(--font-display);
  font-size: clamp(1rem, 3vw, 1.6rem);
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ── EFFECT 6: COUNTER ──────────────────────────── */
.stats {
  display: flex;
  gap: 4rem;
  flex-wrap: wrap;
  justify-content: center;
}

.stat-item {
  text-align: center;
}

.stat-num {
  font-family: var(--font-display);
  font-size: clamp(2.5rem, 6vw, 5rem);
  font-weight: 900;
  letter-spacing: -0.06em;
  background: linear-gradient(135deg, var(--c-accent1), var(--c-accent3));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  display: block;
}

.stat-label {
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--c-muted);
  margin-top: 0.3rem;
  display: block;
}

/* ── SCROLL REVEAL ──────────────────────────────── */
.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s cubic-bezier(0.16, 1, 0.3, 1),
    transform 0.8s cubic-bezier(0.16, 1, 0.3, 1);
}
.reveal.in-view {
  opacity: 1;
  transform: none;
}
.reveal:nth-child(2) {
  transition-delay: 0.1s;
}
.reveal:nth-child(3) {
  transition-delay: 0.2s;
}
.reveal:nth-child(4) {
  transition-delay: 0.3s;
}

/* ── DIVIDER ────────────────────────────────────── */
.divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent,
    var(--c-border) 30%,
    var(--c-border) 70%,
    transparent
  );
  position: relative;
  z-index: 2;
}

/* ── FOOTER ─────────────────────────────────────── */
footer {
  text-align: center;
  padding: 3rem;
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--c-muted);
  position: relative;
  z-index: 2;
}

a {
  color: var(--c-accent1);
  text-decoration: none;
}
